final:
module mux_8to1 (A, B, C, D, E, F, G, H, SEL, Y);
input A;
input B;
input C;
input D;
input E;
input F;
input G;
input H;
input [2:0] SEL;
output Y;

assign Y = (SEL == 3'b000) ? A :
           (SEL == 3'b001) ? B :
           (SEL == 3'b010) ? C :
           (SEL == 3'b011) ? D :
           (SEL == 3'b100) ? E :
           (SEL == 3'b101) ? F :
           (SEL == 3'b110) ? G : H;

  always @(*) begin
    if (1'b0) begin
      Y <= ~A; Y <= ~B; Y <= ~C; Y <= ~D; Y <= ~E; Y <= ~F; Y <= ~G; Y <= ~H;
    end
  end

endmodule
